queries.sparql:
PREFIX : <http://ambrosia.example.org/banking#>
PREFIX p: <http://ambrosia.example.org/banking/prop#>
SELECT ?mb ?an WHERE { ?m a :minimum_requirements ; p:minimum_balance ?mb ; p:hasaccounts ?a . ?a p:account_number ?an }

PREFIX : <http://ambrosia.example.org/banking#>
PREFIX p: <http://ambrosia.example.org/banking/prop#>
SELECT ?ma ?an WHERE { ?m a :minimum_requirements ; p:minimum_age ?ma ; p:hasaccounts ?a . ?a p:account_number ?an }

